#!/usr/bin/env bun
import * as p from '@clack/prompts'
import pc from 'picocolors'
import { fetchRepo } from './fetch.js'
import { detect } from './detect.js'
import { installItems } from './install.js'
import type { DetectedItem, ItemType, Provider, InstallMode, InstallScope } from './types.js'

const TYPE_LABELS: Record<ItemType, string> = {
  agent: 'Agent',
  skill: 'Skill',
  command: 'Command',
  hook: 'Hook',
  rule: 'Rule',
}

function cancel(msg = 'Cancelled'): never {
  p.cancel(msg)
  process.exit(0)
}

function plural(n: number, word: string) {
  return `${n} ${word}${n !== 1 ? 's' : ''}`
}

async function main() {
  const url = process.argv[2]
  if (!url) {
    console.error(`Usage: agent <repo-url | owner/repo | local-path>`)
    process.exit(1)
  }

  p.intro(pc.bold(' @onmyway133/agent '))

  // ── Fetch ──────────────────────────────────────────────────────────────────
  const spinner = p.spinner()
  spinner.start('Fetching repository…')
  let repoDir: string
  try {
    repoDir = await fetchRepo(url)
    spinner.stop('Repository ready')
  } catch (err) {
    spinner.stop('Failed to fetch repository')
    p.log.error(String(err))
    process.exit(1)
  }

  // ── Detect ─────────────────────────────────────────────────────────────────
  const detected = detect(repoDir)
  const allItems: DetectedItem[] = [
    ...detected.agents,
    ...detected.skills,
    ...detected.commands,
    ...detected.hooks,
    ...detected.rules,
  ]

  if (allItems.length === 0) {
    p.outro('Nothing detected in this repository')
    process.exit(0)
  }

  // Summary
  const summary = (
    [
      detected.agents.length && plural(detected.agents.length, 'agent'),
      detected.skills.length && plural(detected.skills.length, 'skill'),
      detected.commands.length && plural(detected.commands.length, 'command'),
      detected.hooks.length && plural(detected.hooks.length, 'hook'),
      detected.rules.length && plural(detected.rules.length, 'rule'),
    ] as (string | false)[]
  ).filter(Boolean).join(', ')

  p.log.success(`Detected: ${summary}`)

  // ── Step 1: choose types ───────────────────────────────────────────────────
  const typeOptions = (
    [
      detected.agents.length && { value: 'agent' as ItemType, label: `Agents  (${detected.agents.length})` },
      detected.skills.length && { value: 'skill' as ItemType, label: `Skills  (${detected.skills.length})` },
      detected.commands.length && { value: 'command' as ItemType, label: `Commands  (${detected.commands.length})` },
      detected.hooks.length && { value: 'hook' as ItemType, label: `Hooks  (${detected.hooks.length})` },
      detected.rules.length && { value: 'rule' as ItemType, label: `Rules  (${detected.rules.length})` },
    ] as ({ value: ItemType; label: string } | false)[]
  ).filter(Boolean) as { value: ItemType; label: string }[]

  const selectedTypes = await p.multiselect<ItemType>({
    message: 'What do you want to install?',
    options: typeOptions,
    required: true,
  })
  if (p.isCancel(selectedTypes)) cancel()

  // ── Step 2: choose individual items ────────────────────────────────────────
  const filtered = allItems.filter(i => (selectedTypes as ItemType[]).includes(i.type))

  const selectedItems = await p.multiselect<DetectedItem>({
    message: 'Choose items:',
    options: filtered.map(item => ({
      value: item,
      label: `${pc.dim(TYPE_LABELS[item.type].padEnd(8))}  ${item.name}`,
      hint: item.description,
    })),
    initialValues: filtered,   // all pre-selected
    required: true,
  })
  if (p.isCancel(selectedItems)) cancel()

  // ── Step 3: provider ───────────────────────────────────────────────────────
  const provider = await p.select<Provider>({
    message: 'Choose provider:',
    options: [
      { value: 'claude-code', label: 'Claude Code' },
      { value: 'codex', label: 'Codex' },
    ],
    initialValue: 'claude-code',
  })
  if (p.isCancel(provider)) cancel()

  // ── Step 4: scope ──────────────────────────────────────────────────────────
  const scope = await p.select<InstallScope>({
    message: 'Install scope:',
    options: [
      { value: 'local', label: 'Local  (current project)' },
      { value: 'global', label: 'Global  (~/.claude)' },
    ],
    initialValue: 'local',
  })
  if (p.isCancel(scope)) cancel()

  // ── Step 5: mode ──────────────────────────────────────────────────────────
  const mode = await p.select<InstallMode>({
    message: 'Install mode:',
    options: [
      { value: 'symlink', label: 'Symlink  (recommended)' },
      { value: 'copy', label: 'Copy' },
    ],
    initialValue: 'symlink',
  })
  if (p.isCancel(mode)) cancel()

  // ── Install ────────────────────────────────────────────────────────────────
  const installSpinner = p.spinner()
  installSpinner.start('Installing…')

  const results = await installItems(selectedItems as DetectedItem[], {
    provider: provider as Provider,
    scope: scope as InstallScope,
    mode: mode as InstallMode,
  })

  installSpinner.stop('Done')

  for (const r of results) {
    if (r.success) {
      p.log.success(`${r.item.name}  →  ${r.dest}`)
    } else {
      p.log.error(`${r.item.name}: ${r.error}`)
    }
  }

  p.outro(pc.green('All done!'))
}

main().catch(err => {
  console.error(err)
  process.exit(1)
})
