import {
  mkdirSync, copyFileSync, symlinkSync, unlinkSync,
  existsSync, readFileSync, writeFileSync, appendFileSync,
  readdirSync, statSync,
} from 'fs'
import { join, basename, dirname, resolve } from 'path'
import { homedir } from 'os'
import type { DetectedItem, HookItem, InstallOptions, InstallResult, Provider, InstallScope } from './types.js'

const BASES: Record<Provider, Record<InstallScope, string>> = {
  'claude-code': {
    local: join(process.cwd(), '.claude'),
    global: join(homedir(), '.claude'),
  },
  codex: {
    local: join(process.cwd(), '.codex'),
    global: join(homedir(), '.codex'),
  },
}

export async function installItems(
  items: DetectedItem[],
  options: InstallOptions
): Promise<InstallResult[]> {
  const base = BASES[options.provider][options.scope]
  return Promise.all(items.map(item => installItem(item, base, options.mode)))
}

async function installItem(
  item: DetectedItem,
  base: string,
  mode: InstallOptions['mode']
): Promise<InstallResult> {
  try {
    const dest = doInstall(item, base, mode)
    return { item, dest, success: true }
  } catch (err) {
    return { item, dest: '', success: false, error: String(err) }
  }
}

function doInstall(item: DetectedItem, base: string, mode: InstallOptions['mode']): string {
  switch (item.type) {
    case 'agent':
      return installFile(item.path, join(base, 'agents', basename(item.path)), mode)

    case 'command':
      return installFile(item.path, join(base, 'commands', basename(item.path)), mode)

    case 'skill': {
      // SKILL.md lives inside the skill directory; install the whole directory
      const skillDir = dirname(item.path)
      const dest = join(base, 'skills', basename(skillDir))
      mkdirSync(dirname(dest), { recursive: true })
      if (mode === 'symlink') {
        symlinkSafe(skillDir, dest)
      } else {
        copyDir(skillDir, dest)
      }
      return dest
    }

    case 'rule': {
      mkdirSync(base, { recursive: true })
      const dest = join(base, basename(item.path))
      const content = readFileSync(item.path, 'utf8')
      if (existsSync(dest)) {
        appendFileSync(dest, '\n\n' + content)
      } else {
        writeFileSync(dest, content)
      }
      return dest
    }

    case 'hook': {
      const hookItem = item as HookItem
      const settingsPath = join(base, 'settings.json')
      mkdirSync(base, { recursive: true })
      const settings = existsSync(settingsPath)
        ? JSON.parse(readFileSync(settingsPath, 'utf8'))
        : {}
      if (!settings.hooks) settings.hooks = {}
      const existing: unknown[] = settings.hooks[hookItem.hookEvent] ?? []
      settings.hooks[hookItem.hookEvent] = [...existing, ...hookItem.hookConfigs]
      writeFileSync(settingsPath, JSON.stringify(settings, null, 2))
      return settingsPath
    }
  }
}

function installFile(src: string, dest: string, mode: InstallOptions['mode']): string {
  mkdirSync(dirname(dest), { recursive: true })
  if (mode === 'symlink') {
    symlinkSafe(src, dest)
  } else {
    copyFileSync(src, dest)
  }
  return dest
}

function symlinkSafe(src: string, dest: string): void {
  if (existsSync(dest)) unlinkSync(dest)
  try {
    symlinkSync(resolve(src), dest)
  } catch {
    // Fallback to copy if symlink unsupported (e.g. Windows)
    const stat = statSync(src)
    if (stat.isDirectory()) {
      copyDir(src, dest)
    } else {
      copyFileSync(src, dest)
    }
  }
}

function copyDir(src: string, dest: string): void {
  mkdirSync(dest, { recursive: true })
  for (const entry of readdirSync(src, { withFileTypes: true })) {
    if (entry.name.startsWith('.')) continue
    const srcPath = join(src, entry.name)
    const destPath = join(dest, entry.name)
    if (entry.isDirectory()) {
      copyDir(srcPath, destPath)
    } else {
      copyFileSync(srcPath, destPath)
    }
  }
}
